from dataclasses import dataclass


@dataclass
class SafetyDimension:
    severity: int        # 1–5
    breadth: int         # 1–5
    reversibility: int   # 1–5

    def __post_init__(self) -> None:
        for name, val in [
            ("severity", self.severity),
            ("breadth", self.breadth),
            ("reversibility", self.reversibility),
        ]:
            if not 1 <= val <= 5:
                raise ValueError(f"{name} must be 1–5, got {val}")

    @property
    def safety_impact_score(self) -> int:
        """Product of the three dimensions. Max = 125."""        return self.severity * self.breadth * self.reversibility

    @property
    def risk_band(self) -> str:
        sis = self.safety_impact_score
        if sis >= 60:  return "CRITICAL"
        if sis >= 30:  return "HIGH"
        if sis >= 10:  return "MEDIUM"
        return "LOW"

    @property
    def is_release_blocking(self) -> bool:
        """SIS >= 60 or severity == 5 blocks release unconditionally."""        return self.safety_impact_score >= 60 or self.severity == 5

from __future__ import annotations
from dataclasses import dataclass, field
from enum import Enum
from typing import Optional


class SIAOutcome(Enum):
    APPROVED        = "approved"         # ship as specified
    APPROVED_WITH_MITIGATIONS = "approved_with_mitigations"
    DESCOPED        = "descoped"         # behavior removed from release scope
    DEFERRED        = "deferred"         # moved to a later release cycle
    PENDING         = "pending"          # assessment not yet complete


@dataclass
class BehaviorChange:
    behavior_id: str
    description: str
    behavior_tags: set[str]
    trigger: str                        # what user action triggers this behavior
    affected_user_segment: str          # who can encounter it


@dataclass
class SafetyImpactAssessment:
    sia_id: str
    feature_id: str
    behavior: BehaviorChange
    tier: BehaviorTier
    dimensions: SafetyDimension
    mitigations: list[str] = field(default_factory=list)
    residual_dimensions: Optional[SafetyDimension] = None
    outcome: SIAOutcome = SIAOutcome.PENDING
    reviewer: str = ""
    reviewed_at: str = ""
    notes: str = ""

    @property
    def pre_mitigation_band(self) -> str:
        return self.dimensions.risk_band

    @property
    def post_mitigation_band(self) -> str:
        if self.residual_dimensions:
            return self.residual_dimensions.risk_band
        return self.pre_mitigation_band

    @property
    def is_release_ready(self) -> bool:
        if self.outcome == SIAOutcome.APPROVED:
            return True
        if self.outcome == SIAOutcome.APPROVED_WITH_MITIGATIONS:
            return (
                self.residual_dimensions is not None
                and not self.residual_dimensions.is_release_blocking
                and len(self.mitigations) > 0
            )
        return False

    def summary(self) -> dict:
        return {
            "sia_id": self.sia_id,
            "behavior": self.behavior.description,
            "tier": self.tier.name,
            "pre_sis": self.dimensions.safety_impact_score,
            "pre_band": self.pre_mitigation_band,
            "post_sis": (self.residual_dimensions.safety_impact_score
                         if self.residual_dimensions else None),
            "post_band": self.post_mitigation_band,
            "outcome": self.outcome.value,
            "is_release_ready": self.is_release_ready,
        }

def check_sia_gate(sia: SafetyImpactAssessment, eval_case_count: int) -> list[str]:
    """Return a list of blocking issues. Empty list means the gate passes."""    issues: list[str] = []

    if sia.tier in (BehaviorTier.T0, BehaviorTier.T1) and not sia.reviewer:
        issues.append(f"{sia.sia_id}: T0/T1 behavior requires named reviewer sign-off")

    if sia.dimensions.is_release_blocking and not sia.mitigations:
        issues.append(
            f"{sia.sia_id}: pre-SIS {sia.dimensions.safety_impact_score} is CRITICAL — "            "mitigations required before residual scoring"
        )

    if sia.residual_dimensions and sia.residual_dimensions.is_release_blocking:
        issues.append(
            f"{sia.sia_id}: post-mitigation SIS {sia.residual_dimensions.safety_impact_score} "            "is still CRITICAL — behavior must be descoped or mitigations strengthened"
        )

    if sia.dimensions.severity == 5:
        issues.append(
            f"{sia.sia_id}: severity=5 behavior requires executive sponsor sign-off or descope"
        )

    if sia.tier in (BehaviorTier.T0, BehaviorTier.T1) and eval_case_count < 50:
        issues.append(
            f"{sia.sia_id}: T0/T1 behavior requires ≥ 50 eval cases, got {eval_case_count}"
        )

    return issues


# Gate check for the nutrition example
issues = check_sia_gate(sia, eval_case_count=200)
print(issues)   # []   — gate passes
